import React, { useEffect, useState, useMemo } from "react";
import axios from "axios";
import { Bar, Pie } from "react-chartjs-2";
import "./AdminDashboard.css";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, ArcElement, Tooltip, Legend);

const AdminDashboard = () => {
  const [predictions, setPredictions] = useState([]);
  const [dashboard, setDashboard] = useState({});
  const salaryBuckets = useMemo(() => {
  const buckets = {
    "2-4L": 0,
    "4-6L": 0,
    "6-8L": 0,
    "8-10L": 0,
    "10L+": 0,
  };

  (salaries || []).forEach((s) => {
    if (s >= 200000 && s < 400000) buckets["2-4L"]++;
    else if (s >= 400000 && s < 600000) buckets["4-6L"]++;
    else if (s >= 600000 && s < 800000) buckets["6-8L"]++;
    else if (s >= 800000 && s < 1000000) buckets["8-10L"]++;
    else if (s >= 1000000) buckets["10L+"]++;
  });

  return buckets;
}, [salaries]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await axios.get("http://localhost:5000/admin/dashboard");

        console.log("API RESPONSE:", res.data);

        setPredictions(res.data.predictions || []);
        setDashboard(res.data || {});
      } catch (err) {
        console.log("Error:", err);
      }
    };

    fetchData();
    const interval = setInterval(fetchData, 5000);

    return () => clearInterval(interval);
  }, []);

  // SAFE ML SALARY EXTRACTION
  const salaries = useMemo(() => {
    return (Array.isArray(predictions) ? predictions : [])
      .map((p) => Number(p.predictedSalary))
      .filter((s) => !isNaN(s) && s > 0);
  }, [predictions]);

  return (
    <div className="admin-view">

      {/* SIDEBAR */}
      <aside className="sidebar-container">
        <div className="sidebar-profile">
          <div className="avatar">👤</div>
          <h3>Admin</h3>
        </div>

        <nav className="sidebar-nav">
          <div className="nav-link active">Dashboard</div>
          <div className="nav-link">Manage Users</div>
          <div className="nav-link">Reports</div>
          <div className="nav-link">Settings</div>
        </nav>

        <button
          className="logout-btn"
          onClick={() => {
            localStorage.removeItem("token");
            window.location.href = "/login";
          }}
        >
          Logout
        </button>
      </aside>

      {/* MAIN CONTENT */}
      <main className="content-area">

        <header className="content-header">
          <h2>Admin Dashboard</h2>
          <div className="header-icons">🔔 👤</div>
        </header>

        <div className="scrollable-content">

          {/* STATS */}
          <section className="stats-container">

            <div className="stat-item c1">
              <span className="stat-label">Avg. Salary</span>
              <h2 className="stat-value">
                ₹{dashboard.avgSalary?.toLocaleString(undefined, { maximumFractionDigits: 0 }) || 0}
              </h2>
            </div>

            <div className="stat-item c2">
              <span className="stat-label">Highest Salary</span>
              <h2 className="stat-value">
                ₹{dashboard.highestSalary?.toLocaleString() || 0}
              </h2>
            </div>

            <div className="stat-item c3">
              <span className="stat-label">Lowest Salary</span>
              <h2 className="stat-value">
                ₹{dashboard.lowestSalary?.toLocaleString() || 0}
              </h2>
            </div>

            <div className="stat-item c4">
              <span className="stat-label">Total Users</span>
              <h2 className="stat-value">
                {dashboard.totalUsers || 0}
              </h2>
            </div>

          </section>

          {/* CHARTS */}
          <section className="charts-container">

            <div className="chart-card">
              <h4 className="chart-title">Salary Distribution</h4>
              <div className="chart-box">
              <Bar
  data={{
    labels: Object.keys(salaryBuckets),
    datasets: [
      {
        label: "Users (Per Annum Salary Distribution)",
        data: Object.values(salaryBuckets),
        backgroundColor: "#3b82f6",
      },
    ],
  }}
  options={{ responsive: true, maintainAspectRatio: false }}
/>
              </div>
            </div>

            <div className="chart-card">
              <h4 className="chart-title">User Demographics</h4>
              <div className="chart-box">
                <Pie
                  data={{
                    labels: ["Low", "Mid", "High"],
                    datasets: [
                      {
                        data: [
                          salaries.filter(s => s < 40000).length,
                          salaries.filter(s => s >= 40000 && s <= 80000).length,
                          salaries.filter(s => s > 80000).length,
                        ],
                        backgroundColor: ["#6366f1", "#f59e0b", "#10b981"],
                      },
                    ],
                  }}
                  options={{ responsive: true, maintainAspectRatio: false }}
                />
              </div>
            </div>

          </section>

          {/* TABLE */}
          <section className="table-container">

            <h4 className="table-title">Recent Predictions</h4>

            <table className="custom-table">
              <thead>
                <tr>
                  <th>Email</th>
                  <th>Job Role</th>
                  <th>Location</th>
                  <th>Predicted Salary</th>
                </tr>
              </thead>

              <tbody>
                {predictions.slice(-5).reverse().map((p, i) => (
                  <tr key={i}>
                    <td>{p.email}</td>
                    <td>{p.role}</td>
                    <td>{p.location}</td>
                    <td className="bold-price">
                      ₹{Number(p.predictedSalary || 0).toLocaleString()}
                    </td>
                  </tr>
                ))}
              </tbody>

            </table>

          </section>

        </div>
      </main>
    </div>
  );
};

export default AdminDashboard;
